async function runRecoveryPipeline() {
  const authUrl = coreExports.getInput('sxt-auth-url');
  const authSecret = coreExports.getInput('sxt-auth-secret');
  const apiUrl = coreExports.getInput('sxt-api-url');
  const biscuit = coreExports.getInput('sxt-biscuit');
  const schema = sanitizeSchema(coreExports.getInput('sxt-schema'));
  const contentFetcherUrl = coreExports.getInput('email-content-fetcher-url');
  const emailProvider = coreExports.getInput('email-provider') || '';
  const emailServiceUrl = coreExports.getInput('email-service-url');
  const maxConcurrent = parseInt(coreExports.getInput('pipeline-recovery-max-concurrent') || '10', 10);
  const claimSize = parseInt(coreExports.getInput('recovery-claim-size') || '500', 10);
  const fetchChunkSize = parseInt(coreExports.getInput('pipeline-fetch-chunk-size') || '10', 10);
  const fetchTimeoutMs = parseInt(coreExports.getInput('pipeline-fetch-timeout-ms') || '30000', 10);
  const maxRetries = parseInt(coreExports.getInput('pipeline-max-retries') || '2', 10);

  console.log(
    `[run-recovery-pipeline] starting (maxConcurrent=${maxConcurrent}, claimSize=${claimSize}, fetchChunkSize=${fetchChunkSize}, fetchTimeoutMs=${fetchTimeoutMs})`,
  );

  const jwt = await authenticate(authUrl, authSecret);
  const exec = (sql) => executeSql(apiUrl, jwt, biscuit, sql);

  let totalRecovered = 0;
  let totalDead = 0;
  let usersProcessed = 0;
  const runStart = Date.now();

  // Claim function: get next user with failed rows
  let userQueue = [];
  let userQueueExhausted = false;

  async function claimBatch() {
    // Refill user queue if empty
    if (userQueue.length === 0 && !userQueueExhausted) {
      const users = await exec(dealStates.findUsersWithFailedRows(schema));
      if (!users || users.length === 0) {
        userQueueExhausted = true;
        return null
      }
      userQueue = users;
      console.log(`[run-recovery-pipeline] found ${users.length} users with failed rows`);
    }

    if (userQueue.length === 0) return null

    const user = userQueue.shift();
    const userId = user.USER_ID;

    // Select failed rows for this user
    const rows = await exec(dealStates.selectFailedByUser(schema, userId, claimSize));
    if (!rows || rows.length === 0) return null

    const elapsed = ((Date.now() - runStart) / 1000).toFixed(1);
    console.log(
      `[run-recovery-pipeline] claimed ${rows.length} failed rows for user ${userId} (elapsed: ${elapsed}s)`,
    );

    return { batch_id: `recovery:${userId}`, count: rows.length, attempts: 0, rows, userId }
  }

  // Worker function: check fetchability and update statuses
  async function processRecoveryBatch(batch) {
    const { rows, userId } = batch;
    const batchStart = Date.now();

    const metaByMessageId = new Map(rows.map((r) => [r.MESSAGE_ID, r]));
    const syncStateId = rows[0].SYNC_STATE_ID;
    const messageIds = rows.map((r) => r.MESSAGE_ID);

    // Fetch with metadata-only format
    let emails = [];
    try {
      emails = await fetchEmails(messageIds, metaByMessageId, {
        contentFetcherUrl,
        emailProvider,
        emailServiceUrl,
        userId,
        syncStateId,
        chunkSize: fetchChunkSize,
        fetchTimeoutMs,
        format: 'metadata',
      });
    } catch (err) {
      console.log(
        `[run-recovery-pipeline] fetch failed for user ${userId}: ${err.message}`,
      );
      // All unfetchable on total failure
      emails = [];
    }

    const fetchedMessageIds = new Set(emails.map((e) => e.messageId || e.id));

    // Split into recoverable vs dead
    const recoverableIds = [];
    const deadIds = [];

    for (const row of rows) {
      if (fetchedMessageIds.has(row.MESSAGE_ID)) {
        recoverableIds.push(row.EMAIL_METADATA_ID);
      } else {
        deadIds.push(row.EMAIL_METADATA_ID);
      }
    }

    // Write: reset recoverable to pending (with BATCH_ID = NULL)
    if (recoverableIds.length > 0) {
      const quotedIds = recoverableIds.map((id) => `'${sanitizeId(id)}'`);
      await exec(dealStates.resetToPending(schema, quotedIds));
    }

    // Write: mark dead
    if (deadIds.length > 0) {
      const quotedIds = deadIds.map((id) => `'${sanitizeId(id)}'`);
      await exec(dealStates.updateStatusByIds(schema, quotedIds, STATUS.DEAD));
    }

    totalRecovered += recoverableIds.length;
    totalDead += deadIds.length;
    usersProcessed++;

    const totalMs = Date.now() - batchStart;
    const elapsed = ((Date.now() - runStart) / 1000).toFixed(1);
    console.log(
      `[run-recovery-pipeline] user ${userId}: ${recoverableIds.length} recovered, ${deadIds.length} dead (${totalMs}ms) | total: recovered=${totalRecovered}, dead=${totalDead}, users=${usersProcessed}, elapsed=${elapsed}s`,
    );
  }

  const poolResults = await runPool(claimBatch, processRecoveryBatch, {
    maxConcurrent,
    maxRetries,
    onDeadLetter: async (batch) => {
      console.log(`[run-recovery-pipeline] dead-lettered batch ${batch.batch_id} (${batch.count} rows)`);
    },
  });

  const runMs = Date.now() - runStart;
  console.log(
    `[run-recovery-pipeline] done — recovered=${totalRecovered}, dead=${totalDead}, users=${usersProcessed}, batches=${poolResults.processed}, failed=${poolResults.failed} (${(runMs / 1000).toFixed(1)}s)`,
  );

  return {
    total_recovered: totalRecovered,
    total_dead: totalDead,
    users_processed: usersProcessed,
    batches_processed: poolResults.processed,
    batches_failed: poolResults.failed,
  }
}

var rawSql = "-- Eligible users for scan_complete webhook (first completed LOOKBACK only).\n-- Parity: backend/src/services/dealsync-v2.sync.service.ts — getSyncStatus(), isFirstCompletedSync()\n-- Plan: docs/plans/2026-04-16-scan-complete-w3-cron-tech-spec.md\n-- Placeholders {{EMAIL_CORE_SCHEMA}} and {{DEALSYNC_SCHEMA}} are replaced at runtime (sanitized).\n\nWITH latest_sync AS (\n  SELECT sync_state_id, user_id, created_at, sync_strategy\n  FROM (\n    SELECT\n      id AS sync_state_id,\n      user_id,\n      created_at,\n      sync_strategy,\n      ROW_NUMBER() OVER (PARTITION BY user_id ORDER BY created_at DESC) AS rn\n    FROM {{EMAIL_CORE_SCHEMA}}.sync_states\n  ) ranked\n  WHERE rn = 1\n),\nstatus_inputs AS (\n  SELECT\n    ls.user_id,\n    ls.sync_state_id,\n    ls.created_at AS initiated_at,\n    (SELECT COUNT(*) FROM {{EMAIL_CORE_SCHEMA}}.email_metadata em WHERE em.user_id = ls.user_id) AS total_messages,\n    (\n      SELECT SUM(\n        CASE WHEN ds.status NOT IN ('pending','filtering','pending_classification','classifying')\n          THEN 1 ELSE 0 END\n      )\n      FROM {{DEALSYNC_SCHEMA}}.deal_states ds\n      WHERE ds.user_id = ls.user_id\n    ) AS processed_messages\n  FROM latest_sync ls\n  WHERE ls.sync_strategy = 'LOOKBACK'\n),\ncompleted_candidates AS (\n  SELECT *\n  FROM status_inputs\n  WHERE initiated_at IS NOT NULL\n    AND processed_messages >= total_messages\n),\nprior_lookback_success AS (\n  SELECT ss.user_id, ss.created_at\n  FROM {{EMAIL_CORE_SCHEMA}}.sync_states ss\n  WHERE ss.sync_strategy = 'LOOKBACK'\n    AND EXISTS (\n      SELECT 1\n      FROM {{EMAIL_CORE_SCHEMA}}.sync_events se_s\n      WHERE se_s.sync_state_id = ss.id\n        AND se_s.event IN ('metadata_ingestion_end','content_ingestion_end','completed')\n        AND se_s.created_at = (\n          SELECT MAX(se2.created_at)\n          FROM {{EMAIL_CORE_SCHEMA}}.sync_events se2\n          WHERE se2.sync_state_id = ss.id\n            AND se2.event IN ('metadata_ingestion_end','content_ingestion_end','completed')\n        )\n        AND NOT EXISTS (\n          SELECT 1\n          FROM {{EMAIL_CORE_SCHEMA}}.sync_events se_f\n          WHERE se_f.sync_state_id = ss.id\n            AND se_f.event IN ('metadata_ingestion_failed','content_ingestion_failed')\n            AND se_f.created_at > se_s.created_at\n        )\n    )\n),\neligible AS (\n  SELECT c.*\n  FROM completed_candidates c\n  WHERE NOT EXISTS (\n    SELECT 1\n    FROM prior_lookback_success pls\n    WHERE pls.user_id = c.user_id\n      AND pls.created_at < c.initiated_at\n  )\n),\ndeal_agg AS (\n  SELECT\n    e.user_id,\n    SUM(CASE WHEN d.category = 'new' THEN 1 ELSE 0 END) AS db_new,\n    SUM(CASE WHEN d.category = 'in_progress' THEN 1 ELSE 0 END) AS db_in_progress,\n    SUM(CASE WHEN d.category = 'completed' THEN 1 ELSE 0 END) AS db_completed,\n    SUM(CASE WHEN d.category = 'not_interested' THEN 1 ELSE 0 END) AS db_not_interested,\n    SUM(CASE WHEN d.category = 'likely_scam' THEN 1 ELSE 0 END) AS db_likely_scam,\n    SUM(CASE WHEN d.category = 'low_confidence' THEN 1 ELSE 0 END) AS db_low_confidence\n  FROM eligible e\n  LEFT JOIN {{DEALSYNC_SCHEMA}}.deals d\n    ON d.user_id = e.user_id AND d.updated_at >= e.initiated_at\n  GROUP BY e.user_id\n),\ncontact_agg AS (\n  SELECT\n    e.user_id,\n    COUNT(DISTINCT c.email) AS contacts_added\n  FROM eligible e\n  INNER JOIN {{DEALSYNC_SCHEMA}}.deal_contacts dc\n    ON dc.user_id = e.user_id\n  INNER JOIN {{DEALSYNC_SCHEMA}}.deals d\n    ON d.id = dc.deal_id AND d.user_id = e.user_id AND d.updated_at >= e.initiated_at\n  INNER JOIN {{EMAIL_CORE_SCHEMA}}.contacts c\n    ON c.user_id = dc.user_id AND c.email = dc.email\n  GROUP BY e.user_id\n)\nSELECT\n  e.user_id,\n  e.initiated_at,\n  COALESCE(da.db_new, 0) AS db_new,\n  COALESCE(da.db_in_progress, 0) AS db_in_progress,\n  COALESCE(da.db_completed, 0) AS db_completed,\n  COALESCE(da.db_not_interested, 0) AS db_not_interested,\n  COALESCE(da.db_likely_scam, 0) AS db_likely_scam,\n  COALESCE(da.db_low_confidence, 0) AS db_low_confidence,\n  COALESCE(ca.contacts_added, 0) AS contacts_added\nFROM eligible e\nLEFT JOIN deal_agg da ON da.user_id = e.user_id\nLEFT JOIN contact_agg ca ON ca.user_id = e.user_id\nORDER BY e.initiated_at DESC;\n";

