var srcExports = requireSrc();

/**
 * Firestore read-only check for users/{userId}.scanCompleteSentAt (dedupe before webhook POST).
 * Uses Firestore REST API + google-auth-library (no firebase-admin).
 */


const FIRESTORE_SCOPE = 'https://www.googleapis.com/auth/datastore';

/**
 * @param {unknown} doc — parsed GET document JSON from Firestore REST
 * @returns {boolean} true if scanCompleteSentAt is present (any numeric value)
 */
function firestoreDocumentHasScanCompleteSentAt(doc) {
  const field = doc?.fields?.scanCompleteSentAt;
  if (!field || typeof field !== 'object') return false
  if (field.integerValue != null && field.integerValue !== '') return true
  if (field.doubleValue != null && Number.isFinite(Number(field.doubleValue))) return true
  return false
}

/**
 * @param {{ projectId: string, userId: string, credentials: Record<string, unknown> }} args
 * @returns {Promise<boolean>} true → skip webhook (already sent); false → eligible to POST
 */
async function userHasScanCompleteSentAt({ projectId, userId, credentials }) {
  const auth = new srcExports.GoogleAuth({
    credentials,
    scopes: [FIRESTORE_SCOPE],
  });
  const client = await auth.getClient();
  const { token } = await client.getAccessToken();
  if (!token) throw new Error('Firestore auth: no access token')

  const path = `projects/${encodeURIComponent(projectId)}/databases/(default)/documents/users/${encodeURIComponent(userId)}`;
  const url = `https://firestore.googleapis.com/v1/${path}`;

  const resp = await fetch(url, {
    method: 'GET',
    headers: { Authorization: `Bearer ${token}` },
    signal: AbortSignal.timeout(30000),
  });

  if (resp.status === 404) return false

  if (!resp.ok) {
    const text = await resp.text();
    throw new Error(`Firestore GET ${resp.status}: ${text}`)
  }

  const doc = await resp.json();
  return firestoreDocumentHasScanCompleteSentAt(doc)
}

/**
 * POST scan_complete lifecycle webhook (same auth as daily digest automation).
 * @see backend/src/controllers/dealsync-v2.webhooks.controller.ts
 */

/**
 * @param {string} baseUrl — backend base URL, no trailing slash
 * @param {string} sharedSecret — DEALSYNC_V2_SHARED_SECRET
 * @param {{ userId: string, eventType: string, eventData: object }} body
 * @returns {Promise<{ ok: boolean, status: number, text?: string }>}
 */
async function postScanCompleteWebhook(baseUrl, sharedSecret, body) {
  const root = baseUrl.replace(/\/+$/, '');
  const url = `${root}/dealsync-v2/webhooks`;
  const resp = await fetch(url, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-shared-secret': sharedSecret,
    },
    body: JSON.stringify(body),
    signal: AbortSignal.timeout(120000),
  });
  const text = await resp.text();
  if (!resp.ok) {
    return { ok: false, status: resp.status, text }
  }
  return { ok: true, status: resp.status, text }
}

/**
 * Cron: eligible first LOOKBACK completions → Firestore dedupe → POST /dealsync-v2/webhooks (scan_complete).
 * @see docs/plans/2026-04-16-scan-complete-w3-cron-tech-spec.md
 */
async function runEmitScanCompleteWebhooks() {
  const authUrl = coreExports.getInput('sxt-auth-url', { required: true });
  const authSecret = coreExports.getInput('sxt-auth-secret', { required: true });
  const apiUrl = coreExports.getInput('sxt-api-url', { required: true });
  const biscuit = coreExports.getInput('sxt-biscuit', { required: true });
  const dealsyncSchema = sanitizeSchema(coreExports.getInput('sxt-schema', { required: true }));
  const emailCoreSchema = sanitizeSchema(coreExports.getInput('email-core-schema') || 'EMAIL_CORE_STAGING');

  const backendBaseUrl = coreExports.getInput('dealsync-backend-base-url', { required: true });
  const sharedSecret = coreExports.getInput('dealsync-v2-shared-secret', { required: true });
  const saJsonRaw = coreExports.getInput('firestore-service-account-json', { required: true });
  let firestoreProjectId = coreExports.getInput('firestore-project-id') || '';
  const concurrency = Math.max(
    1,
    parseInt(coreExports.getInput('scan-complete-webhook-concurrency') || '5', 10),
  );

  let credentials;
  try {
    credentials = JSON.parse(saJsonRaw);
  } catch {
    throw new Error('firestore-service-account-json must be valid JSON')
  }
  if (!firestoreProjectId && typeof credentials.project_id === 'string') {
    firestoreProjectId = credentials.project_id;
  }
  if (!firestoreProjectId) {
    throw new Error('firestore-project-id is required (or project_id in service account JSON)')
  }

  const sql = buildScanCompleteEligibilitySql(emailCoreSchema, dealsyncSchema);
  const jwt = await authenticate(authUrl, authSecret);
  const exec = (q) => executeSql(apiUrl, jwt, biscuit, q);

  console.log('[emit-scan-complete-webhooks] executing eligibility query');
  const result = await exec(sql);
  const rows = Array.isArray(result) ? result : [];
  console.log(`[emit-scan-complete-webhooks] eligibility rows=${rows.length}`);

  let scanned = rows.length;
  let skippedDeduped = 0;
  let posted = 0;
  let errors = 0;

  for (let i = 0; i < rows.length; i += concurrency) {
    const chunk = rows.slice(i, i + concurrency);
    await Promise.all(
      chunk.map(async (row) => {
        let userId;
        try {
          userId = getRowUserId(row);
        } catch (err) {
          console.log(`[emit-scan-complete-webhooks] skip invalid row: ${err.message}`);
          errors++;
          return
        }

        try {
          const alreadySent = await userHasScanCompleteSentAt({
            projectId: firestoreProjectId,
            userId,
            credentials,
          });
          if (alreadySent) {
            skippedDeduped++;
            console.log(`[emit-scan-complete-webhooks] skip dedupe userId=${userId}`);
            return
          }

          const body = rowToScanCompleteWebhookBody(row);
          const res = await postScanCompleteWebhook(backendBaseUrl, sharedSecret, body);
          if (!res.ok) {
            errors++;
            console.log(
              `[emit-scan-complete-webhooks] POST failed userId=${userId} status=${res.status} body=${(res.text || '').slice(0, 500)}`,
            );
            return
          }
          posted++;
          console.log(`[emit-scan-complete-webhooks] posted userId=${userId}`);
        } catch (err) {
          errors++;
          console.log(`[emit-scan-complete-webhooks] error userId=${userId ?? '?'}: ${err.message}`);
        }
      }),
    );
  }

  const summary = { scanned, skippedDeduped, posted, errors };
  console.log(`[emit-scan-complete-webhooks] done ${JSON.stringify(summary)}`);
  return summary
}

const COMMANDS = {
  'sync-deal-states': runSyncDealStates,
  eval: runEval,
  'eval-compare': runEvalCompare,
  'run-filter-pipeline': runFilterPipeline,
  'run-classify-pipeline': runClassifyPipeline,
  'run-recovery-pipeline': runRecoveryPipeline,
  'emit-scan-complete-webhooks': runEmitScanCompleteWebhooks,
};

async function run() {
  let command = 'unknown';
  try {
    command = coreExports.getInput('command', { required: true });
    const handler = COMMANDS[command];
    if (!handler) {
      coreExports.setFailed(
        `Unknown command: "${command}". Available: ${Object.keys(COMMANDS).join(', ')}`,
      );
      return
    }
    console.log(`[dealsync] command=${command} starting`);
    const result = await handler();
    console.log(`[dealsync] command=${command} success`);
    coreExports.setOutput('success', 'true');
    // If result is already a string (e.g. encrypted output), don't double-stringify
    coreExports.setOutput('result', typeof result === 'string' ? result : JSON.stringify(result));
  } catch (error) {
    console.log(`[dealsync] command=${command} FAILED: ${error.message}`);
    console.log(`[dealsync] stack: ${error.stack}`);
    coreExports.setOutput('success', 'false');
    coreExports.setOutput('error', error.message);
    coreExports.setOutput('error_stack', error.stack || '');
    coreExports.setFailed(error.message);
    throw error
  }
}

run().catch(() => process.exit(1));
